"""
extract_2d_descriptors.py

This script generates 2‑D molecular descriptors for the 10 k QM9 subset:
* Morgan (ECFP) fingerprints (radius=2, 2048 bits)
* Coulomb matrices derived from 2‑D coordinates generated by RDKit

The output is written to ``data/processed/features_2d.parquet`` as a
parquet file with three columns:
  - ``molecule_id``: integer index of the molecule in the subset
  - ``fingerprint`` : list of 0/1 integers (length 2048)
  - ``coulomb``    : list of floats representing the flattened, zero‑padded
                    Coulomb matrix (size = max_atoms²)

The script is deliberately lightweight and has no external configuration;
it can be invoked directly:

    python projects/001-predicting-molecular-dipole-moments/code/data/extract_2d_descriptors.py

The script will raise a clear ``FileNotFoundError`` if the required
``molecules_10k.parquet`` subset is missing, mirroring the behaviour of
other data‑processing steps.
"""

from __future__ import annotations

import argparse
import sys
from pathlib import Path
from typing import List

import numpy as np
import pandas as pd
from rdkit import Chem
from rdkit.Chem import AllChem

# -------------------------------------------------------------------------
# Helper functions
# -------------------------------------------------------------------------

def load_subset(subset_path: Path) -> pd.DataFrame:
    """Load the 10 k QM9 subset parquet file."""
    if not subset_path.is_file():
        raise FileNotFoundError(f"Subset parquet not found at {subset_path}")
    return pd.read_parquet(subset_path)

def mol_to_fingerprint(mol: Chem.Mol, radius: int = 2, n_bits: int = 2048) -> List[int]:
    """Return an ECFP (Morgan) fingerprint as a list of 0/1 integers."""
    fp = AllChem.GetMorganFingerprintAsBitVect(mol, radius, nBits=n_bits)
    arr = np.zeros((n_bits,), dtype=int)
    AllChem.DataStructs.ConvertToNumpyArray(fp, arr)
    return arr.tolist()

def mol_to_coulomb_matrix(mol: Chem.Mol, max_atoms: int) -> List[float]:
    """
    Compute a Coulomb matrix for a molecule using RDKit‑generated 2‑D coordinates.

    The matrix is zero‑padded to ``max_atoms × max_atoms`` and then flattened
    row‑major.
    """
    # Ensure the molecule has a conformer (2‑D coordinates are sufficient)
    if mol.GetNumConformers() == 0:
        # Generate a 2‑D conformer
        AllChem.Compute2DCoords(mol)

    conf = mol.GetConformer()
    zs = [atom.GetAtomicNum() for atom in mol.GetAtoms()]
    positions = np.array([conf.GetAtomPosition(i) for i in range(mol.GetNumAtoms())],
                         dtype=float)  # shape (n, 3)

    n = len(zs)
    cm = np.zeros((max_atoms, max_atoms), dtype=float)

    # Fill Coulomb matrix
    for i in range(n):
        for j in range(n):
            if i == j:
                cm[i, j] = 0.5 * zs[i] ** 2.4
            else:
                dist = np.linalg.norm(positions[i] - positions[j])
                if dist == 0.0:
                    # Avoid division by zero – set a large value
                    cm[i, j] = 0.0
                else:
                    cm[i, j] = zs[i] * zs[j] / dist
    # Flatten row‑major
    return cm.flatten().tolist()

def compute_descriptors(df: pd.DataFrame) -> pd.DataFrame:
    """
    Compute Morgan fingerprints and Coulomb matrices for all molecules in ``df``.
    The input dataframe must contain a column named ``smiles``.
    """
    if "smiles" not in df.columns:
        raise KeyError("Input dataframe must contain a 'smiles' column.")

    # Determine the maximum number of atoms across the subset for padding
    max_atoms = df["smiles"].apply(lambda s: Chem.MolFromSmiles(s).GetNumAtoms()).max()

    records = []
    for idx, row in df.iterrows():
        smiles = row["smiles"]
        mol = Chem.MolFromSmiles(smiles)
        if mol is None:
            # Skip invalid SMILES but keep index for traceability
            continue
        # Add explicit hydrogens to have a more realistic atom count for Coulomb matrix
        mol = Chem.AddHs(mol)
        AllChem.Compute2DCoords(mol)

        fp = mol_to_fingerprint(mol)
        cm = mol_to_coulomb_matrix(mol, max_atoms)

        records.append(
            {
                "molecule_id": int(idx),
                "fingerprint": fp,
                "coulomb": cm,
            }
        )
    return pd.DataFrame.from_records(records)

# -------------------------------------------------------------------------
# Main entry point
# -------------------------------------------------------------------------

def main(argv: List[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        description="Generate 2D Morgan fingerprints and Coulomb matrices for the QM9 subset."
    )
    parser.add_argument(
        "--subset-path",
        type=Path,
        default=Path("data/processed/molecules_10k.parquet"),
        help="Path to the parquet file containing the 10k QM9 subset.",
    )
    parser.add_argument(
        "--output-path",
        type=Path,
        default=Path("data/processed/features_2d.parquet"),
        help="Path where the resulting 2D descriptors parquet will be written.",
    )
    args = parser.parse_args(argv)

    try:
        subset_df = load_subset(args.subset_path)
    except FileNotFoundError as exc:
        sys.stderr.write(str(exc) + "\n")
        return 1

    descriptors_df = compute_descriptors(subset_df)

    # Ensure output directory exists
    args.output_path.parent.mkdir(parents=True, exist_ok=True)
    descriptors_df.to_parquet(args.output_path, index=False)

    print(f"2D descriptors written to {args.output_path}")
    return 0

if __name__ == "__main__":
    sys.exit(main())
